import java.util.Scanner;

public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[][] towers = new int[N][2];
            int[][] skyscrapers = new int[M][2];
            for (int i = 0; i < N; i++) {
                towers[i][0] = sc.nextInt();
                towers[i][1] = sc.nextInt();
            }
            for (int i = 0; i < M; i++) {
                skyscrapers[i][0] = sc.nextInt();
                skyscrapers[i][1] = sc.nextInt();
            }
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int dx = towers[j][0] - towers[i][0];
                    int dy = towers[j][1] - towers[i][1];
                    int gcd_val = gcd(dx, dy);
                    dx /= gcd_val;
                    dy /= gcd_val;
                    int flag = 1;
                    for (int k = 0; k < M; k++) {
                        int dx2 = skyscrapers[k][0] - towers[i][0];
                        int dy2 = skyscrapers[k][1] - towers[i][1];
                        int gcd_val2 = gcd(dx2, dy2);
                        dx2 /= gcd_val2;
                        dy2 /= gcd_val2;
                        if (dx == dx2 && dy == dy2) {
                            flag = 0;
                            break;
                        }
                    }
                    for (int k = 0; k < N; k++) {
                        if (k == i || k == j) continue;
                        int dx2 = towers[k][0] - towers[i][0];
                        int dy2 = towers[k][1] - towers[i][1];
                        int gcd_val2 = gcd(dx2, dy2);
                        dx2 /= gcd_val2;
                        dy2 /= gcd_val2;
                        if (dx == dx2 && dy == dy2) {
                            flag = 0;
                            break;
                        }
                    }
                    if (flag) count++;
                }
            }
            System.out.println(count);
        }
    }
}

